script:
(function (root_element) {
  const root = root_element.querySelector("#fbr_fiscal_year_kpi_block");
  if (!root) return;
  const $ = (selector) => root.querySelector(selector);
  const chartCanvas = $("#fbr_kpi_sales_purchase_chart");
  const visibleSeries = { sales: true, purchases: true };
  let lastData = null;

  function money(value) {
    return Math.round(Number(value || 0)).toLocaleString();
  }

  function num(value) {
    return Math.round(Number(value || 0)).toLocaleString();
  }

  function setText(selector, value) {
    const element = $(selector);
    if (element) element.textContent = value;
  }

  function setChange(selector, value) {
    const element = $(selector);
    if (!element) return;
    const numeric = Number(value || 0);
    element.textContent = `${numeric >= 0 ? "+" : ""}${numeric.toFixed(1)}%`;
    element.classList.toggle("bad", numeric < 0);
  }

  function roundedRect(ctx, x, y, width, height, radius) {
    const r = Math.min(radius, Math.abs(width) / 2, Math.abs(height) / 2);
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + width - r, y);
    ctx.quadraticCurveTo(x + width, y, x + width, y + r);
    ctx.lineTo(x + width, y + height);
    ctx.lineTo(x, y + height);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  }

  function drawVerticalLabel(ctx, text, x, y, maxTop, maxBottom) {
    ctx.save();
    ctx.font = "800 10px Segoe UI, sans-serif";
    ctx.fillStyle = "#111827";
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";
    const safeY = Math.min(Math.max(y, maxTop + 24), maxBottom - 24);
    ctx.translate(x, safeY);
    ctx.rotate(-Math.PI / 2);
    ctx.fillText(text, 0, 0);
    ctx.restore();
  }

  function drawBarChart(canvas, labels, sales, purchases) {
    if (!canvas) return;
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.parentElement.getBoundingClientRect();
    const width = Math.max(680, rect.width || 900);
    const height = Math.max(280, rect.height || 300);
    canvas.width = width * dpr;
    canvas.height = height * dpr;
    canvas.style.width = width + "px";
    canvas.style.height = height + "px";
    const ctx = canvas.getContext("2d");
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.clearRect(0, 0, width, height);

    const active = [];
    if (visibleSeries.sales) active.push({ key: "sales", color: "#2da9e1", values: sales });
    if (visibleSeries.purchases) active.push({ key: "purchases", color: "#47c878", values: purchases });
    if (!active.length) return;

    const allValues = active.flatMap((series) => series.values).map((value) => Math.abs(Number(value || 0)));
    const maxValue = Math.max(...allValues, 1);
    const chart = { left: 58, right: 14, top: 18, bottom: 38 };
    const chartWidth = width - chart.left - chart.right;
    const chartHeight = height - chart.top - chart.bottom;
    const groupWidth = chartWidth / Math.max(labels.length, 1);
    const barWidth = Math.max(12, Math.min(42, (groupWidth * 0.72) / active.length));
    const gap = 3;

    ctx.font = "10px Segoe UI, sans-serif";
    ctx.strokeStyle = "#eef2f7";
    ctx.fillStyle = "#334155";
    ctx.lineWidth = 1;
    ctx.textAlign = "left";
    for (let i = 0; i <= 4; i++) {
      const y = chart.top + (chartHeight / 4) * i;
      ctx.beginPath();
      ctx.moveTo(chart.left, y);
      ctx.lineTo(width - chart.right, y);
      ctx.stroke();
      const tick = Math.round(maxValue - (maxValue / 4) * i);
      ctx.fillText(tick.toLocaleString(), 0, y + 3);
    }

    labels.forEach((label, index) => {
      const center = chart.left + groupWidth * index + groupWidth / 2;
      const totalBarWidth = active.length * barWidth + (active.length - 1) * gap;
      active.forEach((series, seriesIndex) => {
        const value = Number(series.values[index] || 0);
        const barHeight = (Math.abs(value) / maxValue) * chartHeight;
        const x = center - totalBarWidth / 2 + seriesIndex * (barWidth + gap);
        const y = chart.top + chartHeight - barHeight;
        ctx.fillStyle = series.color;
        roundedRect(ctx, x, y, barWidth, barHeight, 2);
        ctx.fill();
        const labelText = Math.round(value).toLocaleString();
        const labelY = barHeight > 70 ? y + Math.min(28, barHeight / 2) : y - 8;
        drawVerticalLabel(ctx, labelText, x + barWidth / 2, labelY, chart.top, chart.top + chartHeight);
      });
      ctx.fillStyle = "#334155";
      ctx.font = "10px Segoe UI, sans-serif";
      ctx.textAlign = "center";
      ctx.fillText(label, center, height - 12);
    });
    ctx.textAlign = "left";
  }

  function render(data) {
    lastData = data;
    const summary = data.summary || {};
    const sales = data.sales || {};
    const purchases = data.purchases || {};
    setText("#fbr_kpi_period", `${data.company || ""} · ${data.period_label || "Last fiscal year"}`);
    setText("#fbr_kpi_sales_exclusive", money(sales.exclusive));
    setText("#fbr_kpi_sales_exclusive_line", money(sales.exclusive));
    setText("#fbr_kpi_sales_tax", money(sales.tax));
    setText("#fbr_kpi_sales_inclusive", money(sales.inclusive));
    setText("#fbr_kpi_expenses", money(summary.expenses));
    setText("#fbr_kpi_direct_expenses", money(summary.direct_expenses));
    setText("#fbr_kpi_indirect_expenses", money(summary.indirect_expenses));
    setText("#fbr_kpi_direct_expenses_pct", `${Number(summary.direct_expenses_pct || 0).toFixed(1)}%`);
    setText("#fbr_kpi_indirect_expenses_pct", `${Number(summary.indirect_expenses_pct || 0).toFixed(1)}%`);
    setText("#fbr_kpi_profit", money(summary.profit));
    setText("#fbr_kpi_margin", `${Number(summary.margin || 0).toFixed(1)}%`);
    setText("#fbr_kpi_sales_count", num(sales.invoice_count));
    setText("#fbr_kpi_submitted", num(sales.submitted_count));
    setText("#fbr_kpi_draft", num(sales.draft_count));
    setText("#fbr_kpi_returns", num(sales.return_count));
    setText("#fbr_kpi_fbr_success", num(sales.fbr_success_count));
    setText("#fbr_kpi_fbr_success_line", num(sales.fbr_success_count));
    setText("#fbr_kpi_fbr_pending", num(sales.fbr_pending_count));
    setText("#fbr_kpi_purchase_count", num(purchases.purchase_count));
    setText("#fbr_kpi_purchase_total", money(purchases.purchase_total));
    setChange("#fbr_kpi_revenue_change", summary.revenue_change);
    setChange("#fbr_kpi_expenses_change", summary.expenses_change);
    setChange("#fbr_kpi_profit_change", summary.profit_change);
    setChange("#fbr_kpi_margin_change", summary.margin_change);
    const trend = data.trend || {};
    drawBarChart(chartCanvas, trend.labels || [], trend.sales || [], trend.purchases || []);
  }

  root.querySelectorAll(".fbr-kpi-legend button").forEach((button) => {
    button.addEventListener("click", function () {
      const series = this.dataset.series;
      visibleSeries[series] = !visibleSeries[series];
      this.classList.toggle("active", visibleSeries[series]);
      if (lastData) render(lastData);
    });
  });

  frappe.call({
    method: "fbr_integration.custom_dashboard_api.fiscal_year_kpi_block_data",
    callback: function (r) {
      render(r.message || {});
    },
    error: function () {
      root.innerHTML = '<div class="fbr-kpi-empty">Unable to load fiscal year summary.</div>';
    },
  });

  window.addEventListener("resize", frappe.utils.debounce(function () {
    if (lastData) render(lastData);
  }, 300));
})(root_element);

style:
.fbr-kpi-block{font-family:Inter,Segoe UI,system-ui,sans-serif;background:#eef1f5;padding:10px;border-radius:14px;color:#0f172a;}
.fbr-kpi-head{display:flex;justify-content:space-between;align-items:center;margin:0 0 10px;gap:10px;}
.fbr-kpi-title{font-size:16px;font-weight:800;color:#0f172a;margin:0;}
.fbr-kpi-subtitle{font-size:11px;color:#64748b;margin-top:2px;}
.fbr-kpi-grid{display:grid;grid-template-columns:repeat(6,minmax(148px,1fr));gap:10px;margin-bottom:12px;}
.fbr-kpi-card{position:relative;overflow:hidden;background:#fff;border:1px solid #e5e7eb;border-radius:12px;padding:12px 14px;min-height:92px;box-shadow:0 8px 20px rgba(15,23,42,.06);}
.fbr-kpi-card:after{content:"";position:absolute;right:-18px;top:-20px;width:58px;height:58px;border-radius:50%;opacity:.18;background:var(--accent,#94a3b8);}
.fbr-kpi-label{font-size:11px;font-weight:700;color:#64748b;margin-bottom:5px;}
.fbr-kpi-value{font-size:18px;font-weight:800;color:var(--accent,#0f172a);line-height:1.15;}
.fbr-kpi-change{font-size:11px;font-weight:800;margin-top:5px;color:#059669;}
.fbr-kpi-change.bad{color:#dc2626;}
.fbr-kpi-lines{font-size:11px;line-height:1.45;margin-top:5px;color:#334155;}
.fbr-kpi-lines b{font-weight:800;color:#0f172a;}.fbr-kpi-lines small{font-weight:800;color:#64748b;}
.fbr-kpi-chart-card{background:#fff;border:1px solid #e5e7eb;border-radius:14px;padding:14px;box-shadow:0 8px 20px rgba(15,23,42,.06);}
.fbr-kpi-chart-head{display:flex;justify-content:space-between;align-items:flex-start;gap:12px;margin-bottom:8px;}
.fbr-kpi-chart-title{font-size:16px;font-weight:800;margin:0;color:#0f172a;}
.fbr-kpi-chart-sub{font-size:12px;color:#64748b;margin:2px 0 0;}
.fbr-kpi-legend{display:flex;gap:8px;flex-wrap:wrap;}
.fbr-kpi-legend button{display:flex;align-items:center;gap:6px;border:1px solid #cbd5e1;background:#fff;color:#334155;border-radius:999px;padding:5px 10px;font-size:11px;font-weight:800;cursor:pointer;}
.fbr-kpi-legend button.active{background:#eff6ff;border-color:#60a5fa;color:#0f172a;}
.fbr-kpi-legend .dot{width:10px;height:10px;border-radius:999px;display:inline-block;}.fbr-kpi-legend .sales{background:#2da9e1;}.fbr-kpi-legend .purchases{background:#47c878;}
.fbr-kpi-chart-wrap{height:300px;position:relative;overflow:hidden;}
.fbr-kpi-empty{padding:18px;text-align:center;color:#64748b;font-weight:700;}
@media (max-width:1200px){.fbr-kpi-grid{grid-template-columns:repeat(3,minmax(150px,1fr));}}
@media (max-width:700px){.fbr-kpi-grid{grid-template-columns:1fr;}.fbr-kpi-head,.fbr-kpi-chart-head{align-items:flex-start;flex-direction:column;}}
